import { useContext } from 'react';

import { AnnotationsStateContext } from '../../contexts/AnnotationsStateContext.js';
import type { SelectionState, TooltipState } from '../../types/state.js';

export const useSetState = () => {
  const { setState } = useContext(AnnotationsStateContext);

  return setState;
};

export const useSetStateTooltip = () => {
  const setState = useSetState();

  return (newTooltipState: Partial<TooltipState>) => {
    setState((prev) => ({
      ...prev,
      tooltip: {
        ...prev.tooltip,
        ...newTooltipState,
      },
    }));
  };
};

export const useSetStateSelection = () => {
  const setState = useSetState();

  return (newSelectionState: Partial<SelectionState>) => {
    setState((prev) => ({
      ...prev,
      selection: {
        ...prev.selection,
        ...newSelectionState,
      },
    }));
  };
};
